/* ── Single select ── */
<Select
  options={options}
  value={value}
  onChange={setValue}
  placeholder='Select an option...'
  theme='border'
/>

/* ── Borderless theme ── */
<Select
  theme='borderless'
  options={options}
  value={value}
  onChange={setValue}
/>

/* ── With leading icon ── */
<Select
  leadingIcon={<ListIcon />}
  options={options}
  value={value}
/>

/* ── Multiselect ── */
<MultiSelect
  options={options}
  value={selected}          // string[]
  onChange={setSelected}
  placeholder='Select options...'
/>

/* ── CSS tokens ── */
.dt-select {
  height: 32px;
  padding: 0 10px;
  border: 1px solid var(--n3);
  border-radius: 6px;
  background: #fff;
  display: flex;
  align-items: center;
  gap: 6px;
  cursor: pointer;
}
.dt-select:hover { background: var(--n2); }
.dt-select.open   { border: 2px solid var(--b6); }
.dt-select.filled { border-color: var(--n5); }
.dt-select:disabled { background: var(--n1); opacity: .55; }

.dt-select--borderless {
  border-color: transparent;
  background: transparent;
}
.dt-select--borderless:hover { background: var(--n2); }

.dt-select-chip {
  height: 20px;
  padding: 0 6px;
  background: var(--b1);
  border: 1px solid var(--b3);
  border-radius: 999px;
  font: 400 12px/1 var(--font-sans);
  color: var(--b6);
  display: inline-flex;
  align-items: center;
  gap: 3px;
}

.dt-select-menu {
  position: absolute;
  top: calc(100% + 4px);
  left: 0;
  right: 0;
  background: #fff;
  border: 1px solid var(--n3);
  border-radius: 6px;
  box-shadow: 0 4px 16px rgba(0,0,0,.12);
  z-index: 100;
  padding: 4px 0;
}
.dt-select-option {
  height: 36px;
  padding: 0 12px;
  display: flex;
  align-items: center;
  font: 400 14px/20px var(--font-sans);
  color: var(--n7);
  cursor: pointer;
}
.dt-select-option:hover { background: var(--b1); color: var(--b7); }
